INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$URL-based transformations$q$, $q$Resize, crop, rotate, and compress images by appending parameters like w_250,q_50 to the request URL, with no separate API calls required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Modern format output$q$, $q$Serves AVIF, WebP, and MozJPEG-compressed JPEG alongside standard PNG and GIF, using dedicated encoders for better compression than default ImageMagick output.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Automatic caching$q$, $q$Transformed images are cached after the first request so repeat requests for the same parameters are served instantly without reprocessing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Face detection and blurring$q$, $q$Built-in face detection can be used to intelligently crop around faces or to blur faces for privacy-sensitive image use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Docker-first deployment$q$, $q$Ships as a single Docker image, with a documented path to be running in around 10 minutes on inexpensive AWS or DigitalOcean instances.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Kubernetes and serverless support$q$, $q$A published Helm chart supports Kubernetes deployments, and a one-click deployment path exists for running Flyimg as a serverless container on Google Cloud Platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Access controls and signed URLs$q$, $q$Domain allowlisting with wildcard patterns and URL signature generation restrict who can request transformations against a given Flyimg instance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Managed SaaS option$q$, $q$A fully managed, production-ready version of Flyimg is available directly at flyimg.io for teams that prefer not to run the infrastructure themselves.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Free to self-host with no per-transformation or bandwidth fees beyond infrastructure costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Fast to deploy thanks to Docker packaging, Helm chart, and documented cloud deployment paths$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Strong compression via AVIF, WebP, and MozJPEG output formats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Full control over data residency and image pipeline, avoiding vendor lock-in to a commercial image CDN$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Active open-source community with donation-based (Open Collective) sustainability model$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$AGPL-3.0 licensing imposes source-sharing obligations on organizations that modify and expose Flyimg as a network service$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Self-hosting requires ongoing operational effort (scaling, monitoring, security patching) that managed competitors absorb$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Managed flyimg.io pricing is not transparently published, making cost comparison against Cloudinary or imgix harder upfront$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$No disclosed company backing, formal support SLA, or enterprise contract structure typical of commercial image CDNs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Smaller ecosystem and fewer integrations than large commercial players like Cloudinary$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Is Flyimg free to use?$q$, $q$Yes. The self-hosted, open-source core of Flyimg is free under the AGPL-3.0 license; you only pay for the compute, storage, and bandwidth of the infrastructure you run it on. A separate managed SaaS option exists at flyimg.io for teams that prefer not to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$What image formats does Flyimg support?$q$, $q$Flyimg can output AVIF, WebP, MozJPEG-optimized JPEG, PNG, and GIF, and it fetches and processes most common source image formats via ImageMagick.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$How is Flyimg different from imgproxy or Cloudinary?$q$, $q$Flyimg and imgproxy are both open-source, self-hostable image processing servers, while Cloudinary is a fully managed commercial SaaS. Flyimg is distinguished by its Docker-first packaging, MozJPEG/AVIF-focused compression, and the option to use the maintainers' own managed flyimg.io service instead of self-hosting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$What license does Flyimg use?$q$, $q$Flyimg is licensed under AGPL-3.0. The project originally used the permissive MIT license and moved to AGPL-3.0 to prevent SaaS providers from running a competing hosted service based on the code without contributing changes back.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Can Flyimg run on Kubernetes or serverless platforms?$q$, $q$Yes. The project publishes a Helm chart for Kubernetes deployments and documents a one-click path to deploy Flyimg as a serverless container on Google Cloud Platform, in addition to standard Docker hosting on any VPS.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Who maintains Flyimg?$q$, $q$Flyimg is a community-maintained open-source project hosted under the flyimg GitHub organization, funded through donations via Open Collective rather than venture capital, with development associated with developer Sadok Ferjani.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Self-hosted image CDN for e-commerce$q$, $q$Online stores and product catalogs use Flyimg to resize and optimize product photography on demand instead of paying per-transformation fees to a commercial image CDN.$q$, $q$E-commerce teams and PIM platforms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Cost-controlled image pipeline for high-traffic apps$q$, $q$Applications with steady, high-volume image traffic self-host Flyimg to avoid the recurring bandwidth and transformation costs of managed services once usage reaches a scale where self-hosting is cheaper.$q$, $q$Engineering teams at scale-stage companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Privacy-sensitive image processing$q$, $q$Organizations that need to keep image data on infrastructure they control, or that need built-in face blurring for compliance reasons, run Flyimg internally rather than sending images to a third-party API.$q$, $q$Privacy-conscious developers and regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["AGPL-3.0 licensed source code","Docker, Helm, and serverless deployment options","All core transformation and caching features","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$Managed flyimg.io$q$, $q$Contact for pricing$q$, $q$Not publicly disclosed$q$, NULL, $q$["Fully managed, production-ready hosting","No infrastructure to operate","Public demo environment available","Same transformation API as self-hosted version"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Flyimg is a self-hosted, open-source image processing server distributed as a Docker container. It fetches an original image, applies resize, crop, rotate, or compression operations described in the request URL, caches the output, and serves the optimized file, effectively letting a team run a private, Cloudinary-style image CDN on its own infrastructure.$q$, $q$The project is maintained on GitHub under the flyimg organization and funded through community donations via Open Collective, rather than venture capital. A managed, fully hosted version is also available directly from the maintainers at flyimg.io for teams that prefer not to operate the infrastructure themselves.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include URL-parameter-based transformations (width, quality, cropping, rotation), output in AVIF, WebP, MozJPEG-optimized JPEG, PNG, and GIF, automatic caching of transformed results, face detection and face blurring, and security controls such as domain allowlisting and signed URLs to prevent abuse of an open endpoint.$q$, $q$Deployment flexibility is a major selling point: Flyimg ships as a Docker image, a Helm chart for Kubernetes, and documents a one-click deployment path to Google Cloud Platform as a serverless container, in addition to running on the cheapest available VPS providers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source, self-hosted core of Flyimg is free under the AGPL-3.0 license (the project originally used the permissive MIT license before moving to AGPL-3.0). Running it costs only whatever compute, storage, and bandwidth the hosting infrastructure requires.$q$, $q$Flyimg also offers a managed SaaS at flyimg.io with a public demo at demo.flyimg.io, aimed at teams that want the same transformation capabilities without operating the Docker infrastructure. Specific pricing tiers for the managed service are not publicly documented and should be confirmed directly with the provider.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90850fdb-68e2-47bf-bb23-ea2ccb2848e1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$GPS and cellular device location$q$, $q$Locate a device using GPS when available, falling back to cellular network-based positioning when GPS is unavailable or disabled.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Remote lock and ring$q$, $q$Lock a lost device remotely or trigger it to ring at full volume to help locate it nearby.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Remote photo capture$q$, $q$Trigger the device's camera remotely to capture a picture of its surroundings, useful for identifying who has the device.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Remote factory reset$q$, $q$Wipe a device remotely as a last resort if it cannot be recovered, protecting personal data from unauthorized access.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$SMS command channel$q$, $q$Every core command also works by sending a gated SMS to the device, providing a control path that does not depend on the device having an active data or FMD Server connection.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$End-to-end encrypted data$q$, $q$Location data and photos are encrypted client-side using RSA-3072 and an Argon2id-derived AES-GCM key, so the server only ever stores ciphertext.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Lightweight Docker deployment$q$, $q$Official Alpine, Debian, and distroless Docker images (roughly 40 to 160 MB) make self-hosting straightforward behind any reverse proxy.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$No Google dependency$q$, $q$Works fully independently of Google Play Services and Google accounts, making it compatible with de-Googled Android distributions like GrapheneOS and LineageOS.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Fully open source and self-hostable, avoiding dependency on Google or Apple location services$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Strong end-to-end encryption design means even the server operator cannot read location data or photos$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Works on de-Googled Android devices where Google's own Find My Device does not function$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Dual control paths (web interface and SMS) provide redundancy if internet connectivity is unavailable$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Very small resource footprint, runs comfortably on inexpensive VPS or home server hardware$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Requires technical comfort with Docker and reverse proxy configuration for self-hosting$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$No official first-party managed hosting; managed options come from third-party providers, not the core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$No formal company backing, support SLA, or roadmap guarantees typical of commercial device-tracking services$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Feature set is narrower than mainstream platform services (no cross-device family sharing dashboard comparable to Apple Find My, for example)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$SMS-based commands depend on the device retaining a working SIM and cellular signal$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Is FMD Server free to use?$q$, $q$Yes. FMD Server is open-source software licensed under GPLv3-or-later, and self-hosting it costs nothing beyond the infrastructure it runs on. Third-party managed hosting is also available for a fee for users who do not want to self-host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Can FMD Server read my location data?$q$, $q$No, by design. Location data and photos are encrypted on the device using an RSA-3072 keypair protected by an Argon2id-derived AES-GCM key, so the server only stores ciphertext and cannot decrypt it without the user's password.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Does FMD Server require Google Play Services?$q$, $q$No. FMD Android and FMD Server are designed to work entirely independently of Google Play Services and Google accounts, which is why the project is popular on de-Googled Android distributions like GrapheneOS and LineageOS.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$How do I self-host FMD Server?$q$, $q$FMD Server ships as official Docker images (Alpine, Debian, and distroless variants) that listen on port 8080 behind a reverse proxy handling TLS, with a mounted volume to persist the SQLite database across restarts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Can I control FMD without an internet connection?$q$, $q$Yes. Every core FMD command also works over SMS, gated by a PIN or a whitelist of trusted phone numbers, so a lost device can still be located or locked even without a working data connection.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Are there managed hosting options for FMD Server?$q$, $q$Yes. Third-party providers such as DANIAN offer fully managed FMD Server hosting starting around EUR 9 per month, and the project is also packaged for one-click deployment on platforms like Cloudron, Hostinger, and Dokploy.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$De-Googled Android device recovery$q$, $q$Users running GrapheneOS, LineageOS, or other de-Googled Android builds self-host FMD Server to regain find-my-phone functionality that Google's own service cannot provide without Play Services.$q$, $q$Privacy-focused GrapheneOS and LineageOS users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Self-hosted family device tracking$q$, $q$Privacy-conscious households run a shared FMD Server instance to track and remotely manage multiple family members' Android devices without sending location data to a third party.$q$, $q$Privacy-conscious families and individuals$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Managed find-my-device for non-technical users$q$, $q$Users who want FMD's privacy model but lack the skills to self-host use third-party managed hosting providers to get a running FMD Server instance for a small monthly fee.$q$, $q$Non-technical privacy-focused users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPLv3-or-later licensed source code","Official Docker images (Alpine, Debian, distroless)","Full feature set including location, lock, ring, photo, and wipe","End-to-end encrypted data storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$Third-Party Managed Hosting (e.g. DANIAN)$q$, $q$From approximately EUR 9/month$q$, $q$Monthly$q$, NULL, $q$["Fully managed FMD Server instance","Automated backups and updates","SSL and monitoring included","Human support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FMD Server is the open-source, self-hostable backend for FMD (Find My Device), an Android application that locates, locks, rings, photographs, and can factory-reset a lost or stolen phone without relying on Google Play Services or a Google account.$q$, $q$Written in Go with SQLite storage, FMD Server is distributed as small Docker images and is developed by a maintainer known as Nulide under the fmd-foss project on GitLab, with the Android client separately published on F-Droid.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include GPS and cellular device location, remote lock, remote ring, remote photo capture, and remote factory reset, all controllable either through the FMD Server web interface or via SMS commands gated by a PIN or a whitelist of trusted numbers.$q$, $q$Its defining technical feature is end-to-end confidentiality: location data is protected with an RSA-3072 keypair guarded by an Argon2id-derived AES-GCM key, so the server stores only ciphertext and the operator running an instance cannot read a user's location or photos without that user's own password.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FMD Server is free and open source (GPLv3-or-later) to self-host; the only cost is the infrastructure it runs on, and official Docker images range from about 40 MB (distroless) to 160 MB (Debian-based).$q$, $q$For users who do not want to self-host, third-party managed hosting is available, such as DANIAN's fully managed FindMyDeviceServer offering starting at roughly EUR 9 per month, plus one-click packages on platforms like Cloudron, Hostinger, and Dokploy.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a27aac5d-ba7b-4216-98f7-3b5ba2d3cd80', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$folkX browser extension$q$, $q$A Chrome extension that adds contacts to a Folk workspace with one click directly from LinkedIn, Gmail, Crunchbase, X, and dozens of other sites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$AI-powered contact enrichment$q$, $q$Automatically fills in missing fields like email, phone, job title, company, and industry using AI-driven third-party data providers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Spreadsheet-style Tables$q$, $q$Contacts and companies are shown in flexible, filterable, sortable Tables instead of rigid CRM record forms, making the data model adaptable to different workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Pipeline and deal management$q$, $q$Sales pipelines, deals, and custom objects can be layered on top of the core Tables to track opportunities through defined stages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Email sequences and campaigns$q$, $q$Built-in tools for sending email campaigns and multi-step follow-up sequences directly from the CRM.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Magic Fields$q$, $q$AI-generated custom fields that automatically populate based on other data in a contact or company record.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Native communication sync$q$, $q$Automatic sync with email, calendar, and WhatsApp so interaction history is captured without manual logging.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$5,000+ integrations$q$, $q$Connects to thousands of third-party tools via native integrations and automation platforms like Zapier and Make.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Fast setup and modern, spreadsheet-like interface that is easier to learn than traditional enterprise CRMs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$folkX extension makes capturing and enriching LinkedIn contacts significantly faster than manual data entry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Flexible Table-based data model adapts to sales, recruiting, fundraising, and partnership use cases without heavy customization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Strong AI enrichment and Magic Fields reduce manual research work$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Backed by a credible investor (Accel) and the eFounders/Hexa startup studio track record$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$No perpetual free plan, only a 14-day trial, unlike some competitors such as HubSpot$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Per-seat pricing means costs scale directly with team size, which can get expensive for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$API access, dashboards, and custom objects are gated behind the Premium tier and above$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Less mature enterprise sales and marketing automation depth compared to HubSpot or Salesforce$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Enrichment and AI field usage are capped by monthly credit limits that vary by plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$How much does Folk CRM cost?$q$, $q$Folk has three per-seat plans: Standard at $30/month ($24/month billed annually), Premium at $60/month ($48/month billed annually), and Enterprise at $100/month ($80/month billed annually), all priced per member per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Does Folk have a free plan?$q$, $q$No, Folk does not offer a perpetual free plan. It offers a 14-day free trial that requires no credit card and defaults to Premium-level features during the trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Who founded Folk and when?$q$, $q$Folk was founded in 2020 in Paris by Thibaud Elziere, Jean-Yves Poilleux, and Simo Lemhandez within the eFounders startup studio (now called Hexa), and raised a EUR 2.8 million seed round led by Accel in September 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$What is folkX?$q$, $q$folkX is Folk's Chrome browser extension that lets users add contacts to their CRM with one click directly from LinkedIn, Gmail, Crunchbase, X, and other websites, with AI enrichment automatically filling in missing contact details.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$How does Folk compare to HubSpot?$q$, $q$HubSpot has a more generous free plan and deeper enterprise sales and marketing automation, while Folk offers a more modern, faster-to-set-up interface and stronger LinkedIn-based contact capture through folkX, making it better suited to smaller, relationship-centric teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Who is Folk designed for?$q$, $q$Folk is designed primarily for small teams of roughly 20 to 50 people managing relationships in sales, recruiting, fundraising, and partnerships, rather than large enterprise sales organizations.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Startup fundraising tracking$q$, $q$Founders use Folk to track investor conversations, capture contacts from LinkedIn, and manage fundraising pipelines from first outreach to closed round.$q$, $q$Startup founders raising venture capital$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Lightweight sales CRM for small teams$q$, $q$Small sales teams use Folk as a faster-to-adopt alternative to heavyweight CRMs, relying on folkX to build prospect lists directly from LinkedIn.$q$, $q$Sales teams at small and mid-size companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Recruiting and candidate pipeline management$q$, $q$Recruiters and hiring teams use Folk's Tables and pipelines to track candidates captured from LinkedIn profiles through interview stages.$q$, $q$In-house recruiters and talent teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Standard$q$, $q$$30/member/month ($24/member/month billed annually)$q$, $q$Monthly or Annual$q$, NULL, $q$["Pipeline management","Email campaigns","Contact enrichment (500 credits/month)","AI Assistants and Magic Fields (2,000 AI field credits/month)","folkX LinkedIn extension","Email, calendar, and WhatsApp sync","5,000+ integrations","2,000 messages/member/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Premium$q$, $q$$60/member/month ($48/member/month billed annually)$q$, $q$Monthly or Annual$q$, NULL, $q$["All Standard features","Custom objects and Deals","Email sequences","Workspace roles","Dashboards","API access","1,000 enrichment credits/month","5,000 AI field credits/month","5,000 messages/member/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$Enterprise$q$, $q$$100/member/month ($80/member/month billed annually)$q$, $q$Monthly or Annual$q$, NULL, $q$["All Standard and Premium features","Custom usage limits","Security controls","Group-level permissions","Dedicated account manager and 1:1 onboarding","Custom integrations","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Folk is a relationship-focused CRM founded in Paris in 2020 by Thibaud Elziere, Jean-Yves Poilleux, and Simo Lemhandez within the eFounders (now Hexa) startup studio. It raised a EUR 2.8 million seed round led by Accel in September 2021.$q$, $q$The product organizes contacts and companies in flexible, spreadsheet-style Tables rather than rigid CRM records, and is built around folkX, a browser extension for one-click contact capture and AI-driven enrichment from LinkedIn, Gmail, and other web sources.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Folk includes pipeline management, email campaigns and sequences, AI-generated Magic Fields, native email/calendar/WhatsApp sync, and access to more than 5,000 integrations through connectors like Zapier and Make.$q$, $q$Higher tiers add custom objects and deals, workspace roles, dashboards, and API access, positioning Folk as flexible enough to support sales, recruiting, fundraising, and partnership workflows from one shared workspace.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Folk uses per-seat subscription pricing with three tiers: Standard at $30/month ($24/month billed annually), Premium at $60/month ($48/month billed annually), and Enterprise at $100/month ($80/month billed annually), all priced per member.$q$, $q$There is no perpetual free plan, but Folk offers a 14-day free trial with no credit card required, and the trial defaults to Premium-level features regardless of the plan a user intends to purchase.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7f48b7ce-b6d6-4a03-9a89-b0fe089765f6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Real-time tax calculation$q$, $q$Tax Engine calculates VAT, GST, sales tax, and other indirect taxes at the moment a transaction occurs, across more than 200 countries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Global e-invoicing compliance$q$, $q$Generates, transmits, and validates compliant electronic invoices to meet real-time tax reporting mandates across accounts receivable and accounts payable in 100+ countries.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Tax ID validation (Lookup)$q$, $q$Instantly validates VAT, GST, and other tax identifiers across more than 115 countries via a single API.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Single API integration$q$, $q$Replaces country-by-country point solutions with one API that covers tax calculation, invoicing, and ID validation across many jurisdictions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Configurable tax determination$q$, $q$Tax rules can be configured to match a business's specific product taxability and jurisdictional requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Acquired PwC Indirect Tax Edge technology$q$, $q$Following its 2026 acquisition of PwC's Indirect Tax Edge, Fonoa gained additional enterprise-grade tax determination technology and customer relationships.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Enterprise case-study track record$q$, $q$Published customer stories document measurable ROI, including a reported $45M ROI for a global communications platform and $6.8M in avoided VAT risk for a global cloud provider.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$API-first architecture designed for direct integration into checkout, billing, and invoicing flows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Broad global coverage spanning 200+ countries for tax calculation and 100+ for e-invoicing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Founding team's Uber background gives credibility with other high-growth digital marketplaces$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Well-capitalized with $110M+ in total disclosed funding and strong investor backing (Index Ventures, Coatue, Headline)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Expanded enterprise capability through the 2026 acquisition of PwC's Indirect Tax Edge$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$No published fixed pricing, requiring a sales conversation for exact cost estimates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Usage-based pricing can be harder to forecast than flat-fee software for finance teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Primarily suited to companies with meaningful transaction volume and engineering resources to integrate an API, less accessible to very small businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Competes against long-established incumbents (Avalara, Vertex, Sovos) with deeper enterprise sales and ERP integration history$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$When was Fonoa founded and by whom?$q$, $q$Fonoa was founded in 2019 by Davor Tremac, Filip Sturman, and Ivan Ivankovic, three former Uber employees who experienced firsthand how difficult it is to correctly calculate and report taxes across many countries at scale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$How much funding has Fonoa raised?$q$, $q$Fonoa has raised funding across a seed round (Index Ventures, end of 2020), a $20.5M Series A (2021), a $60M Series B (2022, led by Coatue), and a $110M Series C (May 2026, led by Headline), alongside which it acquired PwC's Indirect Tax Edge platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$What does Fonoa's platform do?$q$, $q$Fonoa provides APIs for real-time indirect tax calculation (Tax Engine), global e-invoicing and tax reporting compliance (E-Invoicing), and tax ID validation (Lookup) across 100+ countries.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$How is Fonoa priced?$q$, $q$Fonoa uses a usage-based pricing model driven by API call volume or transaction volume, with custom enterprise pricing available for businesses with high or specialized needs; it does not publish a fixed rate card.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Who are Fonoa's customers?$q$, $q$Fonoa's published case studies name customers including Zoom, Uber, Booking.com, and Remote.com, generally large digital platforms and marketplaces transacting across many countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Who are Fonoa's main competitors?$q$, $q$Fonoa competes with established indirect tax and e-invoicing compliance vendors such as Avalara, Vertex, Sovos, and Thomson Reuters ONESOURCE, though it differentiates through an API-first, developer-native approach built for digital platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Global marketplace tax compliance$q$, $q$Digital marketplaces and platforms operating across dozens of countries integrate Fonoa's Tax Engine to calculate correct VAT, GST, and sales tax at checkout in real time.$q$, $q$Global online marketplaces and platforms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$E-invoicing mandate compliance$q$, $q$Companies operating in countries with real-time e-invoicing and tax reporting requirements use Fonoa's E-Invoicing API to stay compliant across accounts receivable and payable without building country-specific integrations.$q$, $q$Finance and tax teams at multinational companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$B2B tax ID validation and fraud prevention$q$, $q$Businesses processing B2B transactions use Fonoa Lookup to instantly validate customer VAT or GST numbers before applying tax exemptions, reducing compliance risk and fraud.$q$, $q$B2B SaaS and e-commerce finance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$Usage-Based / Custom$q$, $q$Contact for pricing$q$, $q$Usage-based (per API call or transaction volume)$q$, NULL, $q$["Access to Tax Engine, E-Invoicing, and/or Lookup APIs","Coverage across 100-200+ countries depending on product","Configurable tax determination rules","Custom enterprise pricing for high-volume or specialized needs"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Fonoa is a Dublin-headquartered tax technology company founded in 2019 by three former Uber employees, Davor Tremac, Filip Sturman, and Ivan Ivankovic, who built the platform to solve the global tax compliance scaling problem they experienced firsthand at a hypergrowth marketplace.$q$, $q$The company provides API-first infrastructure for real-time tax calculation, tax ID validation, and e-invoicing compliance, used by digital platforms and marketplaces operating across 100+ countries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Fonoa's product suite includes Tax Engine for real-time VAT, GST, and sales tax calculation in 200+ countries, E-Invoicing for compliant electronic invoicing and real-time tax reporting, and Lookup for validating tax IDs across 115+ countries.$q$, $q$In 2026 Fonoa acquired PwC's Indirect Tax Edge platform alongside a $110 million Series C round, expanding its enterprise-grade tax determination capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Fonoa does not publish a fixed rate card. Pricing is usage-based, driven by API call volume or transaction volume processed through the platform, with feature-access tiers layered on top.$q$, $q$Enterprise customers with high or specialized volume requirements negotiate custom pricing directly with Fonoa's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3cfd8357-fdc8-4d45-99e4-e5c8d322206d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Automated producer order lists$q$, $q$Generates and emails automatic weekly PDF order lists to producers so they know exactly what to prepare and deliver.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Flexible delivery rhythms$q$, $q$Supports weekly, bi-weekly, monthly, and one-off collective bulk order cycles to match different cooperative operating models.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Deposit and credit system$q$, $q$Members pay into a running account balance and shop cashlessly against it, removing the need to handle cash at pickup.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Producer login area$q$, $q$Manufacturers and producers get their own login to manage and update their product listings directly.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Network module for multi-coop producers$q$, $q$Producers supplying multiple food cooperatives running separate FoodCoopShop instances can synchronize product data centrally instead of updating each shop individually.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$In-person self-service and barcode scanning$q$, $q$Supports walk-in, self-service shopping with optional barcode scanning at the point of sale for shops with a physical storefront.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Cash register and invoice integration$q$, $q$Integrates with physical cash registers and generates invoices for hybrid retail operations serving both members and walk-in customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Multi-language support$q$, $q$Available in German, English, and Russian, reflecting use across the German-speaking cooperative movement and beyond.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Purpose-built for the specific operational needs of food cooperatives and small food retailers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Free to self-host as open-source software, with an optional professionally managed hosting alternative$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Long track record of active maintenance since 2014 with at least one release per year$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Deposit/credit system and producer order automation remove significant manual admin work for volunteer-run coops$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Growing community of roughly 54 active initiatives and 22 contributors as of 2026$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Primarily documented and supported in German, which may create a language barrier outside German-speaking Europe$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$In-person support is limited to organizations within roughly 50km of Scharnstein, Austria$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Hosted service pricing (EUR 1,290 setup plus EUR 619/year) may be significant for very small or newly formed cooperatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Smaller ecosystem and contributor base compared to general-purpose e-commerce platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Self-hosting requires PHP/MySQL server administration skills if not using the paid hosted option$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Is FoodCoopShop free to use?$q$, $q$Yes, the open-source software can be downloaded and self-hosted for free. A paid, professionally hosted and installed version is also available for a one-time EUR 1,290 installation fee plus an EUR 619 annual service fee (both including VAT).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Who created FoodCoopShop and when?$q$, $q$FoodCoopShop was created by Mario Rothauer, a software engineer in Scharnstein, Upper Austria, starting in May 2014 after he founded a local food cooperative called Fairteiler and needed software to run it. It became open source in 2016 following a Netidee grant.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$What technology is FoodCoopShop built on?$q$, $q$FoodCoopShop is built on the CakePHP framework with a MySQL database, and the project provides a Docker-based development environment for contributors and self-hosters.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Can FoodCoopShop be used by shops that are not member cooperatives?$q$, $q$Yes. Since around 2018, the platform has expanded beyond formally structured food cooperatives to also serve commercial organic (bio) shops and farm shops, including in-person, self-service retail with barcode scanning and cash register integration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$How does FoodCoopShop compare to Foodsoft?$q$, $q$Both are open-source, self-hosted platforms for managing food cooperatives, but FoodCoopShop is built on CakePHP/MySQL and has expanded into serving commercial bio-shops and point-of-sale retail, while Foodsoft is built on Ruby on Rails and originates from the broader German food coop movement's shared hosting platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$What languages does FoodCoopShop support?$q$, $q$FoodCoopShop supports German, English, and Russian, reflecting its primary user base in German-speaking Europe and its wider international adoption.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Member-run food cooperative ordering$q$, $q$Volunteer-run food cooperatives use FoodCoopShop to manage weekly or bi-weekly member ordering, producer communication, and cashless deposit accounts.$q$, $q$Volunteer-run food cooperatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Organic and farm shop retail management$q$, $q$Bio-shops and farm shops use FoodCoopShop's in-person, self-service features with barcode scanning and cash register integration to run day-to-day retail operations.$q$, $q$Independent organic shops and farm shops$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Multi-cooperative producer coordination$q$, $q$Producers who supply several different food cooperatives use the network module to synchronize product listings across multiple FoodCoopShop instances from a single source.$q$, $q$Local producers supplying multiple cooperatives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source codebase","Docker-based development environment","Community support via project channels","All core ordering, deposit, and retail features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$Hosted and Installed$q$, $q$EUR 1,290 one-time installation fee (incl. 20% VAT) + EUR 619/year service fee (incl. VAT)$q$, $q$One-time setup + Annual$q$, NULL, $q$["Professional installation on a domain of your choice","Ongoing hosting and maintenance","In-person support within ~50km of Scharnstein, Austria","Remote paid support for distant locations"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FoodCoopShop is open-source software for managing the ordering, inventory, deposit accounts, and point-of-sale needs of food cooperatives, organic shops, and farm shops. It was created in May 2014 by Mario Rothauer in Scharnstein, Upper Austria, after he founded a local food cooperative and needed software to run it.$q$, $q$The project went open source in 2016 following a Netidee grant, and by 2026 it is used by roughly 54 initiatives, with 119 GitHub stars and 22 active contributors, built on CakePHP and MySQL with a Docker-based development environment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform automates the weekly order cycle: producers get their own login area, automatic PDF order-list emails are sent to producers, and the system supports weekly, bi-weekly, monthly, and one-off collective delivery rhythms.$q$, $q$A cashless deposit and credit system lets members shop against a running account balance, and the platform also supports self-service, in-person shopping with barcode scanning and cash register integration for shops that serve walk-in customers, plus a network module that syncs product data for producers supplying multiple cooperatives.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FoodCoopShop is free to download and self-host under its open-source license. For organizations that prefer not to run their own server, the project offers a professionally hosted and installed version.$q$, $q$The hosted option costs a one-time installation fee of EUR 1,290 (including 20% VAT) plus an ongoing annual service fee of EUR 619 (including VAT); domain registration is billed separately, and support is available in person near Scharnstein or remotely via paid support further away.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('640f5401-b849-4bad-b457-90e05c828c55', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Shared product catalog$q$, $q$Maintains a catalog of products synced with the cooperative's chosen suppliers for members to order from.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Member online ordering$q$, $q$Lets cooperative members place orders online ahead of a scheduled collection or delivery day.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Cooperative accounting and bookkeeping$q$, $q$Tracks shared finances, member balances, and supplier payments to keep the cooperative's books transparent.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Volunteer job and task scheduling$q$, $q$Coordinates the rotating volunteer labor (packing orders, deliveries, bookkeeping) that work-share cooperatives rely on to operate.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Multi-cooperative shared hosting$q$, $q$The foodcoops.net platform, run by the Rokoli tech collective, hosts many separate cooperative instances centrally rather than requiring each to self-host.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$React-based webshop component$q$, $q$The companion foodsoft-shop project provides a more modern web storefront that integrates with the core Foodsoft backend.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$AGPL open-source licensing$q$, $q$Licensed under AGPL v3 or later, ensuring that modifications run as a network service must also be released under the same open license.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Community-driven roadmap$q$, $q$Development priorities are shaped through monthly community calls open to users and contributors.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Purpose-built for the specific work-share, non-profit operating model of food cooperatives$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Free and open source under AGPL, with a low-cost shared hosting option available$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Long track record of active use and maintenance dating back to roughly the mid-2000s$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Community-governed development with open monthly calls, giving user cooperatives direct influence over the roadmap$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Combines catalog, ordering, accounting, and job scheduling in a single integrated platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$No formal company, support contract, or SLA behind the software, since it is entirely community-maintained$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Interface and documentation may feel dated compared to modern commercial SaaS tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Primarily documented and supported in German and English, which may limit accessibility elsewhere$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Self-hosting outside the shared foodcoops.net platform requires Ruby on Rails server administration skills$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Narrow focus on the non-profit cooperative model makes it less suited to commercial retail use cases than alternatives like FoodCoopShop$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Is Foodsoft free to use?$q$, $q$Yes. Foodsoft is free and open source under the AGPL v3-or-later license. On the shared foodcoops.net hosting platform, every cooperative gets up to five free user accounts, with additional accounts billed at EUR 1 net per month each.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$What is Foodsoft used for?$q$, $q$Foodsoft manages the core operations of a non-profit food cooperative, including a shared product catalog, member online ordering, accounting, and the volunteer job scheduling that work-share cooperatives depend on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$What technology is Foodsoft built with?$q$, $q$Foodsoft is built with Ruby on Rails and is maintained as an open-source project under the foodcoops GitHub organization, with a companion React-based webshop component called foodsoft-shop.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Who runs foodcoops.net?$q$, $q$The shared Foodsoft hosting platform at foodcoops.net is operated by Rokoli, an IT technology collective, on behalf of many individual food cooperatives across Europe.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$How does Foodsoft differ from FoodCoopShop?$q$, $q$Both are open-source platforms for food cooperatives, but Foodsoft is built on Ruby on Rails and originates from the broader German food coop movement's community-run hosting infrastructure, while FoodCoopShop is built on CakePHP by an individual Austrian founder and has expanded further into point-of-sale retail for commercial bio-shops.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Can I influence Foodsoft's development roadmap?$q$, $q$Yes. Foodsoft's development is community-driven, and users can influence the roadmap by joining the project's monthly community calls.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Work-share food cooperative operations$q$, $q$Volunteer-run cooperatives use Foodsoft to manage supplier catalogs, member ordering, accounting, and the rotating volunteer job assignments the cooperative depends on.$q$, $q$Non-profit, work-share food cooperatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Multi-cooperative shared hosting$q$, $q$Smaller cooperatives without technical resources use the centrally hosted foodcoops.net platform to run Foodsoft without maintaining their own server infrastructure.$q$, $q$Small cooperatives without in-house technical staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Regional cooperative network coordination$q$, $q$National or regional food coop networks (such as in Germany or the Netherlands) adapt and run Foodsoft to standardize ordering and accounting tools across multiple affiliated cooperatives.$q$, $q$Regional food cooperative networks$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["AGPL v3-or-later licensed source code","Full catalog, ordering, accounting, and job scheduling functionality","Community support via forum and monthly calls","Requires own Ruby on Rails server administration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$foodcoops.net Shared Hosting$q$, $q$Free for up to 5 users, then EUR 1 net/month per additional user$q$, $q$Monthly (per additional user account)$q$, NULL, $q$["Centrally hosted Foodsoft instance managed by the Rokoli tech collective","Up to 5 free user accounts per cooperative","No server administration required","Access to community support and roadmap calls"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Foodsoft is an open-source, Ruby on Rails platform for running non-profit food cooperatives, covering shared product catalogs, member ordering, accounting, and the volunteer job scheduling that work-share cooperatives depend on. Its origins trace to the German food cooperative movement of the mid-2000s, with hosting infrastructure history suggesting roots around 2007.$q$, $q$The project is licensed under AGPL v3 or later and is community-governed rather than run by a company, with development historically driven by contributor Benjamin Meichsner and maintained under the foodcoops GitHub organization.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes a shared supplier product catalog, member-facing online ordering, cooperative accounting and bookkeeping, and job/task scheduling to coordinate the rotating volunteer labor that keeps a work-share cooperative running.$q$, $q$A companion project, foodsoft-shop, adds a modern React-based webshop front end on top of the core Foodsoft backend, and the platform supports multiple cooperatives running on a shared, centrally hosted instance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Foodsoft is free and open source to self-host under the AGPL license. A shared hosting platform at foodcoops.net, operated by the Rokoli tech collective, runs instances on behalf of many cooperatives.$q$, $q$On that hosted platform, every cooperative gets up to five free user accounts, with additional accounts billed at just EUR 1 net per month each, a cost-recovery model rather than a profit-driven SaaS price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1807f881-55e3-4c8e-81e1-3548278fad9e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Markdown articles with Liquid tag embeds$q$, $q$Authors publish long-form articles in Markdown and can embed rich content like CodePen, GitHub Gists, and YouTube videos using Liquid tags without writing HTML.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Multi-subforum support$q$, $q$A single Forem deployment can host multiple distinct community spaces, each with its own identity, moderation policies, and onboarding flow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$AI moderation and content tools$q$, $q$Gemini-backed AI services handle comment quality assessment, article enhancement suggestions, spam labeling, and personalized email digest summaries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Reactions, badges, and gamification$q$, $q$Members can react to content and earn badges and achievements that reward consistent participation, driving community engagement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Blazer-powered analytics$q$, $q$A built-in analytics suite lets administrators query platform data directly to understand community activity and growth.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Feature flags and A/B testing$q$, $q$A Flipper-based feature flag system supports controlled feature rollouts and experimentation across a Forem community.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Sidekiq background job monitoring$q$, $q$Admin dashboards for Sidekiq let operators monitor and manage background job processing on their Forem instance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Official self-hosting toolkit$q$, $q$The forem/selfhost project provides documented deployment paths for DigitalOcean, AWS, Google Cloud, and bare-metal infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Proven at real production scale, powering DEV Community with 800,000+ registered users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Completely free and open source with no licensing cost for self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Rich, blogging-forward feature set (Markdown, Liquid embeds, reactions, badges) beyond typical forum software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Built-in AI moderation and content tooling reduces manual moderation workload$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Supports multiple distinct branded communities from a single deployment via subforums$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$No current first-party managed hosting tier; self-hosting requires real cloud infrastructure and Rails operations skills$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$No SLA, managed upgrade path, or enterprise support contract available directly from the Forem team$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Smaller ecosystem of official integrations and support compared to commercial community platforms like Discourse or Circle$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Historical Forem Cloud enterprise hosting option does not appear to be actively offered today, leaving a gap for non-technical organizations$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Is Forem free to use?$q$, $q$Yes, the Forem software is free and open source. Organizations self-host it on their own infrastructure (DigitalOcean, AWS, Google Cloud, or bare metal) using the official forem/selfhost toolkit, at no licensing cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$What is the relationship between Forem and DEV Community?$q$, $q$Forem is the open-source software that was originally built to power DEV Community (dev.to). The company behind DEV, originally Dev Community Inc., rebranded to the Forem Team in October 2020 as it generalized the platform for any community, not just developers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Who founded Forem?$q$, $q$Forem (originally Dev Community Inc.) was founded by Ben Halpern, Jess Lee, and Peter Frank, and is headquartered in New York, New York. The company raised an $11.5 million Series A led by Mayfield.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Does Forem offer managed hosting?$q$, $q$Forem previously offered a paid enterprise hosting tier known as Forem Cloud, but there is no current evidence of it being actively offered. Today, self-hosting via the official forem/selfhost toolkit is the primary deployment path, with no SLA or managed support included.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$What AI features does Forem include?$q$, $q$Forem includes Gemini-backed AI tools for comment quality assessment, article enhancement suggestions, spam labeling, and generating personalized email digest summaries for community members.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$How does Forem compare to Discourse or Circle?$q$, $q$Forem is a fully open-source, self-hostable platform proven at the scale of DEV Community, while Discourse offers both open-source and commercially hosted options, and Circle and Mighty Networks are fully hosted, commercial community-as-a-service products without a self-hosting option.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Developer and technical communities$q$, $q$Organizations build DEV-style communities where members publish technical articles, comment, and build reputation through badges and reactions.$q$, $q$Developer relations and technical community teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Branded customer or fan communities$q$, $q$Companies self-host Forem to run a fully branded, white-label community platform on their own infrastructure rather than a closed, hosted alternative.$q$, $q$Companies building owned customer or fan communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Multi-community media platforms$q$, $q$Organizations running several related but distinct communities use Forem's multi-subforum support to manage them from a single deployment with separate branding and moderation per community.$q$, $q$Media companies and multi-brand community operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source Forem platform via forem/forem on GitHub","Official self-hosting toolkit (forem/selfhost)","Deployable on DigitalOcean, AWS, Google Cloud, or bare metal","No SLA, managed upgrades, or enterprise support included"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Forem is the open-source community platform originally built to power DEV Community (dev.to). Founded by Ben Halpern, Jess Lee, and Peter Frank, the underlying software began in 2016-2017 as 'The Practical Dev' before becoming DEV, and the company rebranded from 'the DEV Team' to 'the Forem Team' in October 2020 as the software was generalized for any community, not just developers.$q$, $q$Headquartered in New York and backed by an $11.5 million Series A led by Mayfield, Forem now operates DEV (800,000+ registered users, roughly 7 million monthly unique visitors), CodeNewbie, and the standalone open-source Forem platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Forem is a blogging-forward social network supporting Markdown articles with Liquid tag embeds (CodePen, GitHub Gists, YouTube), comments, reactions, badges, and multi-subforum support so one deployment can host several distinct branded communities.$q$, $q$Operational tooling includes Gemini-backed AI moderation (comment quality assessment, spam labeling, article enhancement suggestions, personalized digest emails), a Blazer analytics suite, Flipper feature flags for A/B testing, and Sidekiq background job dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Forem software itself is completely free and open source, distributed via the forem/forem GitHub repository with an official self-hosting toolkit (forem/selfhost) for deployment on DigitalOcean, AWS, Google Cloud, or bare metal.$q$, $q$There is currently no active first-party managed hosting tier; self-hosted Forem instances come with no SLA, no managed upgrade path, and no enterprise support contract from the Forem team, unlike the previously offered Forem Cloud enterprise option.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('104c1524-087c-4a12-b6f7-1c69780a1d4b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Lightweight single-binary deployment$q$, $q$Forgejo ships as a single static binary that runs comfortably on as little as 512MB of RAM, making self-hosting practical on inexpensive infrastructure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$GitHub-Actions-compatible CI/CD$q$, $q$Forgejo Actions runs workflows written in GitHub Actions YAML syntax with self-hosted runners, easing migration from GitHub for teams with existing CI pipelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Pull requests, issues, and wiki$q$, $q$Full code review workflow support including pull requests, an issue tracker, and a per-repository wiki, matching core GitHub/GitLab functionality.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Container and package registries$q$, $q$Built-in container registry and package registry support let teams host their own artifacts alongside their source code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$ActivityPub-based federation (ForgeFed)$q$, $q$Forgejo is building federation on the ForgeFed protocol, already supporting federated repository stars across separate instances, with pull request, issue, and identity federation on the roadmap.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$OpenID Connect tokens for Actions$q$, $q$As of v15.0, Forgejo Actions can request signed JWTs that external systems can verify as originating from a specific workflow, avoiding the security risks of static long-lived tokens.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Git LFS and SSH access$q$, $q$Supports Git Large File Storage for managing large binary assets and standard SSH-based repository access.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Community, non-profit governance$q$, $q$Developed under Codeberg e.V., a German non-profit, with governance explicitly structured to avoid the kind of unilateral trademark transfer that led to Forgejo's creation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Fully free and open source with no licensing cost for self-hosting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Nonprofit, community-based governance under Codeberg e.V. reduces the risk of a future for-profit takeover$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Lightweight resource footprint makes self-hosting accessible on modest, inexpensive hardware$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$GitHub-Actions-compatible CI/CD eases migration for teams already using GitHub Actions workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Actively shipping federation features (ForgeFed) that no major competing forge currently matches$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Federation remains an early, in-progress feature; full pull request, issue, and identity federation are not yet delivered$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$No official first-party commercial hosted tier, so non-technical users must rely on third-party or community hosting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Smaller ecosystem of integrations and enterprise support compared to GitHub or GitLab$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Ongoing divergence from Gitea since the 2024 hard fork means the two projects may increasingly require separate evaluation over time$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Why was Forgejo created?$q$, $q$Forgejo was forked from Gitea in October 2022 after the Gitea trademark and domain were transferred to a new for-profit company, Gitea Limited, without community consultation. When contributors' request to place the trademarks under community management was rejected, they forked the project as Forgejo under the non-profit Codeberg e.V.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Is Forgejo free to use?$q$, $q$Yes. Forgejo is free and open source (GPL-licensed) to self-host, with no first-party commercial hosted tier from the project itself. Third-party providers offer paid managed hosting, and Codeberg.org provides free, donation-funded public hosting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$How is Forgejo different from Gitea?$q$, $q$Forgejo started as a soft fork of Gitea that tracked upstream changes, but became a full hard fork in February 2024, diverging permanently after Gitea v1.21. Forgejo is also governed by the non-profit Codeberg e.V. rather than the for-profit Gitea Limited, and moved its overall license from MIT to GPL in August 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Does Forgejo support GitHub Actions workflows?$q$, $q$Yes. Forgejo Actions runs workflows written in GitHub Actions YAML syntax with self-hosted runners, and as of v15.0 supports OpenID Connect tokens for secure, short-lived authentication between workflows and external systems.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$What is ForgeFed and does Forgejo support it?$q$, $q$ForgeFed is an ActivityPub-based federation protocol designed for software forges. Forgejo is actively building on it, with federated repository stars across separate Forgejo instances already shipped, and fuller federation of pull requests, issues, and identities planned for the future.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$How much RAM does Forgejo need to run?$q$, $q$Forgejo ships as a single static binary and is documented to run comfortably on as little as 512MB of RAM, making it practical to self-host on inexpensive VPS infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Self-hosted GitHub alternative$q$, $q$Development teams and organizations self-host Forgejo to get GitHub-like repository hosting, pull requests, issues, and CI/CD while keeping full control of their infrastructure and data.$q$, $q$Developer teams wanting infrastructure control$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$European data sovereignty and public-sector hosting$q$, $q$European companies and public-sector bodies choose Forgejo for its non-profit governance and self-hosting model to keep source code and CI/CD data within jurisdictions they control, avoiding dependency on US-based commercial platforms.$q$, $q$European public-sector organizations and privacy-focused companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Open-source project hosting under community governance$q$, $q$Open-source projects host their code on community-run Forgejo instances like Codeberg.org to avoid dependency on a single for-profit platform vendor.$q$, $q$Open-source maintainers and communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPL-licensed source code (inherited Gitea code remains MIT)","Single static binary, runs on as little as 512MB RAM","Pull requests, issues, wiki, container and package registries","Forgejo Actions CI/CD with self-hosted runners"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$Codeberg.org (Community Hosting)$q$, $q$Free (donation-funded)$q$, $q$N/A$q$, NULL, $q$["Public Forgejo instance run by Codeberg e.V.","Free hosting for open-source projects","Community and non-profit governed","Migrated from Gitea to Forgejo in April 2023"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Forgejo is a self-hosted Git forge, forked from Gitea in October 2022 after Gitea's trademark and domain were transferred to a new for-profit company without community consultation. Forgejo is governed under Codeberg e.V., a German non-profit that also runs the Codeberg.org community Git hosting platform.$q$, $q$It began as a 'soft fork' that tracked upstream Gitea changes, then became a full 'hard fork' in February 2024, diverging permanently after Gitea's v1.21 release. In August 2024 the project moved its overall license from MIT to the GNU GPL.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Forgejo ships as a lightweight single static binary that runs on as little as 512MB of RAM, and includes pull requests, issue tracking, a wiki, a container registry, a package registry, Git LFS, and SSH access.$q$, $q$Forgejo Actions provides GitHub-Actions-compatible CI/CD with self-hosted runners, and the project is actively building ActivityPub-based federation (ForgeFed) toward the long-term goal of interconnected, decentralized forge instances, with federated repository stars already shipped as a first step.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Forgejo is free and open source (GPL-licensed, with inherited Gitea code remaining MIT-licensed) with no first-party commercial hosted tier from the project or Codeberg e.V.$q$, $q$Organizations self-host Forgejo on their own infrastructure at no licensing cost, though third-party providers offer paid managed Forgejo hosting, and Codeberg.org itself offers free, donation-funded public hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1827e10f-a82c-4fb0-8d38-d47e51547c3e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
